1	// Smoke test for the deployed auth-signup-creator edge function.
2	//
3	// Usage: bun run scripts/test/auth-signup-creator.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY in .env (bun auto-loads).
5	//
6	// Asserts:
7	//   1. Fresh { username, tiktok_handle, instagram_handle } → 200 with
8	//      { token, user_id, role:'creator' }
9	//   2. Same body → 409 USERNAME_TAKEN
10	//   3. Fresh username + no handles → 422 HANDLE_REQUIRED
11	//   4. Fresh username + missing body field → 400 INVALID_REQUEST
12	//   5. Fresh username + recycled tiktok handle → 409 HANDLE_TAKEN
13	//   6. Normalized handle: leading '@' is stripped (verified by reusing the
14	//      naked handle against a row created with the '@'-prefixed form)
15	
16	const supabaseUrl = process.env.SUPABASE_URL;
17	const anonKey = process.env.SUPABASE_ANON_KEY;
18	if (!supabaseUrl || !anonKey) {
19	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
20	  process.exit(1);
21	}
22	
23	const endpoint = `${supabaseUrl}/functions/v1/auth-signup-creator`;
24	const baseHeaders = {
25	  "Content-Type": "application/json",
26	  Authorization: `Bearer ${anonKey}`,
27	  apikey: anonKey,
28	};
29	
30	const unique = Date.now();
31	const primary = {
32	  username: `us019_test_${unique}`,
33	  tiktok_handle: `us019_tt_${unique}`,
34	  instagram_handle: `us019_ig_${unique}`,
35	};
36	
37	async function post(body: unknown) {
38	  const res = await fetch(endpoint, {
39	    method: "POST",
40	    headers: baseHeaders,
41	    body: JSON.stringify(body),
42	  });
43	  const data = await res.json().catch(() => null);
44	  return { status: res.status, data };
45	}
46	
47	const first = await post(primary);
48	console.log("first:", first.status, first.data);
49	if (first.status !== 200) process.exit(1);
50	if (
51	  typeof first.data?.token !== "string" ||
52	  typeof first.data?.user_id !== "string" ||
53	  first.data?.role !== "creator"
54	) {
55	  console.error("unexpected 200 body shape");
56	  process.exit(1);
57	}
58	
59	const second = await post(primary);
60	console.log("second:", second.status, second.data);
61	if (second.status !== 409 || second.data?.error !== "USERNAME_TAKEN") {
62	  console.error("expected 409 USERNAME_TAKEN");
63	  process.exit(1);
64	}
65	
66	const third = await post({ username: `us019_test_nohandles_${unique}` });
67	console.log("third:", third.status, third.data);
68	if (third.status !== 422 || third.data?.error !== "HANDLE_REQUIRED") {
69	  console.error("expected 422 HANDLE_REQUIRED");
70	  process.exit(1);
71	}
72	
73	const fourth = await post({ tiktok_handle: `us019_missinguser_${unique}` });
74	console.log("fourth:", fourth.status, fourth.data);
75	if (fourth.status !== 400 || fourth.data?.error !== "INVALID_REQUEST") {
76	  console.error("expected 400 INVALID_REQUEST");
77	  process.exit(1);
78	}
79	
80	// Reuse the primary tiktok handle with a new username → HANDLE_TAKEN.
81	// Prefix with '@' to prove normalization strips it before the RPC compares.
82	const fifth = await post({
83	  username: `us019_test_handlecollide_${unique}`,
84	  tiktok_handle: `@${primary.tiktok_handle}`,
85	});
86	console.log("fifth:", fifth.status, fifth.data);
87	if (fifth.status !== 409 || fifth.data?.error !== "HANDLE_TAKEN") {
88	  console.error("expected 409 HANDLE_TAKEN (proves '@' normalization)");
89	  process.exit(1);
90	}
91	
92	console.log("ok — created user_id:", first.data.user_id);
